{
  "module": "01-permissions.md",
  "group": "01 — Permissions & Runtime Authorization",
  "apiCount": 5,
  "apis": [
    {
      "name": "@ohos.abilityAccessCtrl",
      "purpose": "程序访问控制管理，提供权限校验、用户授权请求、权限状态监听等能力",
      "anchor": "ohosabilityaccessctrl",
      "status": "found"
    },
    {
      "name": "ohos.permission.READ_IMAGEVIDEO",
      "purpose": "读取图片/视频权限声明字符串常量，用于访问相册媒体资源",
      "anchor": "ohospermissionread_imagevideo",
      "status": "found"
    },
    {
      "name": "ohos.permission.WRITE_IMAGEVIDEO",
      "purpose": "写入图片/视频权限声明字符串常量，用于创建/修改相册媒体资源",
      "anchor": "ohospermissionwrite_imagevideo",
      "status": "found"
    },
    {
      "name": "PermissionRequestResult",
      "purpose": "权限请求结果对象，包含请求的权限列表及各自的授权结果",
      "anchor": "permissionrequestresult",
      "status": "found"
    },
    {
      "name": "GrantStatus",
      "purpose": "授权状态枚举: PERMISSION_DENIED(-1)/PERMISSION_GRANTED(0)",
      "anchor": "grantstatus",
      "status": "found"
    }
  ],
  "notableFindings": [
    "ohos.permission.READ_IMAGEVIDEO和ohos.permission.WRITE_IMAGEVIDEO属于user_grant类型的敏感权限，需运行时动态申请",
    "通过Picker方式访问媒体资源可绕过READ_IMAGEVIDEO权限声明",
    "本应用自身写入的媒体文件无需额外申请读权限即可访问",
    "Permissions类型是@kit.AbilityKit导出的联合字符串类型，无独立文档文件，有效值由在线权限列表定义",
    "abilityAccessCtrl.requestPermissionOnSetting可用于用户首次拒绝授权后二次拉起权限设置弹框"
  ],
  "missingApis": []
}

{
  "module": "02-relational-database.md",
  "group": "02 — Relational Database (RDB)",
  "apiCount": 4,
  "apis": [
    {
      "name": "relationalStore",
      "purpose": "关系型数据库模块命名空间，提供 getRdbStore/deleteRdbStore 等顶层函数以及 RdbStore/ResultSet 等类型",
      "anchor": "relationalstore",
      "status": "found"
    },
    {
      "name": "RdbStore",
      "purpose": "管理关系数据库（RDB）的接口，提供 insert/update/delete/query/execute 等 CRUD 操作方法",
      "anchor": "rdbstore",
      "status": "found"
    },
    {
      "name": "ResultSet",
      "purpose": "数据库查询返回的结果集接口，提供行指针移动、字段值读取（getString/getLong/getDouble/getBlob）及关闭方法",
      "anchor": "resultset",
      "status": "found"
    },
    {
      "name": "ValuesBucket",
      "purpose": "数据库插入/更新的键值对数据类型，类型定义为 Record<string, ValueType | Uint8Array | null>",
      "anchor": "valuesbucket",
      "status": "found"
    }
  ],
  "notableFindings": [
    "所有 API 通过 import { relationalStore } from '@kit.ArkData' 导入，ValuesBucket 可单独导入 import { ValueType, ValuesBucket } from '@kit.ArkData'",
    "首批接口从 API version 9 开始支持，getRdbStoreSync 和 insertSync 从 API 12/24 起提供同步版本",
    "单条数据不超过 2MB，字符串单字段不超过 8MB；单次查询不超过 5000 行；大查询建议放在 TaskPool 中",
    "RdbStore 不直接 new 实例化，必须通过 relationalStore.getRdbStore() 获取",
    "ResultSet 使用后必须调用 close() 释放资源"
  ],
  "missingApis": [
    "relationalStore.RdbStore — 已作为 RdbStore 覆盖",
    "relationalStore.ResultSet — 已作为 ResultSet 覆盖"
  ]
}

